case 'work_location_search':$t=trim(at_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,location_code,location_name,location_type,city FROM erp_work_location WHERE status='ACTIVE' AND (?='' OR location_code LIKE ? OR location_name LIKE ? OR location_type LIKE ? OR city LIKE ?) ORDER BY location_type,location_code LIMIT 30",array($t,$like,$like,$like,$like));at_select2($rows,'id',function($r){return $r->location_code.' - '.$r->location_name.' ['.$r->location_type.($r->city?' / '.$r->city:'').']';});
