case 'shift_schedule_search':$t=trim(at_p('term'));$date=trim(at_p('attendance_date'));$like='%'.$t.'%';$w=$date!==''?" AND ? BETWEEN ss.schedule_from AND ss.schedule_to ":"";$p=$date!==''?array($date,$t,$like,$like,$like):array($t,$like,$like,$like);$rows=$db->query("SELECT ss.id,ss.assignment_no,ss.employee_no,e.full_name,ss.shift_code,ss.schedule_from,ss.schedule_to FROM erp_shift_schedule ss JOIN erp_employee_master e ON e.id=ss.employee_id WHERE ss.assignment_status IN ('RELEASED','PLANNED') $w AND (?='' OR ss.assignment_no LIKE ? OR ss.employee_no LIKE ? OR e.full_name LIKE ?) ORDER BY ss.assignment_no LIMIT 30",$p);at_select2($rows,'id',function($r){return $r->assignment_no.' - '.$r->employee_no.' '.$r->full_name.' ['.$r->shift_code.' / '.$r->schedule_from.' sd '.$r->schedule_to.']';});
