case 'save':
  $id=(int)at_p('id');$no=at_c(at_p('attendance_no'));$emp=(int)at_p('employee_id');$date=trim(at_p('attendance_date'));$type=at_c(at_p('attendance_type','REGULAR'));$source=at_c(at_p('attendance_source','MANUAL'));$status=at_c(at_p('attendance_status','DRAFT'));
