  $e=$db->fetch("SELECT id,employee_no,department_code FROM erp_employee_master WHERE id=? LIMIT 1",array($emp));if(!$e)at_json('error','Employee tidak valid.');$dept=at_p('department_code')!==''?at_c(at_p('department_code')):$e->department_code;$ssId=at_p('shift_schedule_id')!==''?(int)at_p('shift_schedule_id'):null;$ssNo=null;$shiftId=at_p('shift_id')!==''?(int)at_p('shift_id'):null;$shiftCode=null;$locId=at_p('work_location_id')!==''?(int)at_p('work_location_id'):null;
