  if($shiftId){$sh=$db->fetch("SELECT id,kode_shift FROM erp_shift WHERE id=? LIMIT 1",array($shiftId));if(!$sh)at_json('error','Shift tidak valid.');$shiftCode=$sh->kode_shift;}
  if($db->fetch("SELECT id FROM erp_attendance WHERE attendance_no=? AND id<>? LIMIT 1",array($no,$id)))at_json('error','Attendance No sudah digunakan.');if($db->fetch("SELECT id FROM erp_attendance WHERE employee_id=? AND attendance_date=? AND id<>? LIMIT 1",array($emp,$date,$id)))at_json('error','Attendance employee di tanggal tersebut sudah ada.');
